import numpy as np
from typing import List, Callable
from scipy.linalg import expm

class VariationalQRBM:
    def __init__(self, n_visible: int, n_hidden: int, n_layers: int = 2):
        self.n_visible = n_visible
        self.n_hidden = n_hidden
        self.n_total = n_visible + n_hidden
        self.n_layers = n_layers
        self.dim = 2 ** self.n_total

        self.n_params = self._count_parameters()
        self.params = np.random.randn(self.n_params) * 0.1

        # Precompute Pauli matrices
        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Y = np.array([[0, -1j], [1j, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

    def _count_parameters(self) -> int:
        params_per_layer = 3 * self.n_total + self.n_visible * self.n_hidden
        return self.n_layers * params_per_layer

    def _single_qubit_gate(self, gate: np.ndarray, qubit: int) -> np.ndarray:
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_total):
            result = np.kron(result, gate if i == qubit else self.I)
        return result

    def _rotation_gate(self, axis: str, theta: float, qubit: int) -> np.ndarray:
        if axis == 'x':
            gate = expm(-1j * theta/2 * self.X)
        elif axis == 'y':
            gate = expm(-1j * theta/2 * self.Y)
        else:
            gate = expm(-1j * theta/2 * self.Z)
        return self._single_qubit_gate(gate, qubit)

    def _rzz_gate(self, theta: float, q1: int, q2: int) -> np.ndarray:
        Z1 = self._single_qubit_gate(self.Z, q1)
        Z2 = self._single_qubit_gate(self.Z, q2)
        ZZ = Z1 @ Z2
        return expm(-1j * theta/2 * ZZ)

    def _build_circuit(self, params: np.ndarray) -> np.ndarray:
        U = np.eye(self.dim, dtype=complex)
        idx = 0

        for layer in range(self.n_layers):
            # Single qubit rotations
            for q in range(self.n_total):
                U = self._rotation_gate('x', params[idx], q) @ U
                idx += 1
                U = self._rotation_gate('y', params[idx], q) @ U
                idx += 1
                U = self._rotation_gate('z', params[idx], q) @ U
                idx += 1

            # ZZ couplings between visible and hidden
            for v in range(self.n_visible):
                for h in range(self.n_hidden):
                    U = self._rzz_gate(params[idx], v, self.n_visible + h) @ U
                    idx += 1

        return U

    def get_state(self, params: np.ndarray = None) -> np.ndarray:
        if params is None:
            params = self.params
        U = self._build_circuit(params)
        psi0 = np.zeros(self.dim, dtype=complex)
        psi0[0] = 1.0
        return U @ psi0

    def get_density_matrix(self, params: np.ndarray = None) -> np.ndarray:
        psi = self.get_state(params)
        return np.outer(psi, psi.conj())

    def compute_energy(self, H: np.ndarray, params: np.ndarray = None) -> float:
        psi = self.get_state(params)
        return np.real(psi.conj() @ H @ psi)

    def train_to_gibbs(self, H: np.ndarray, beta: float, n_iterations: int = 100, learning_rate: float = 0.1):
        for iteration in range(n_iterations):
            grads = np.zeros_like(self.params)
            eps = 1e-4

            for i in range(len(self.params)):
                params_plus = self.params.copy()
                params_plus[i] += eps
                params_minus = self.params.copy()
                params_minus[i] -= eps

                E_plus = self.compute_energy(H, params_plus)
                E_minus = self.compute_energy(H, params_minus)
                grads[i] = (E_plus - E_minus) / (2 * eps)

            self.params -= learning_rate * grads

            if iteration % 20 == 0:
                E = self.compute_energy(H)
                print(f"Iteration {iteration}: Energy = {E:.6f}")

import numpy as np
from scipy.linalg import expm
from typing import Tuple, Dict

class ExpressivenessComparator:
    def __init__(self, n_visible: int, n_hidden: int):
        self.n_visible = n_visible
        self.n_hidden = n_hidden
        self.n_total = n_visible + n_hidden
        self.dim_v = 2 ** n_visible
        self.dim_h = 2 ** n_hidden
        self.dim = 2 ** self.n_total

    def _int_to_binary(self, x: int, n_bits: int) -> np.ndarray:
        return np.array([(x >> i) & 1 for i in range(n_bits)])

    def classical_rbm_distribution(self, W: np.ndarray, a: np.ndarray, b: np.ndarray, beta: float = 1.0) -> np.ndarray:
        probs = np.zeros(self.dim_v)

        for v_idx in range(self.dim_v):
            v = self._int_to_binary(v_idx, self.n_visible)
            energy = -np.dot(a, v)
            for j in range(self.n_hidden):
                activation = b[j] + np.dot(W[:, j], v)
                energy -= np.log(1 + np.exp(beta * activation)) / beta
            probs[v_idx] = np.exp(-beta * energy)

        return probs / np.sum(probs)

    def _build_hamiltonian(self, W: np.ndarray, a: np.ndarray, b: np.ndarray, gamma: float) -> np.ndarray:
        I = np.eye(2, dtype=complex)
        X = np.array([[0, 1], [1, 0]], dtype=complex)
        Z = np.array([[1, 0], [0, -1]], dtype=complex)

        def single_op(op, q):
            result = np.array([[1]], dtype=complex)
            for i in range(self.n_total):
                result = np.kron(result, op if i == q else I)
            return result

        H = np.zeros((self.dim, self.dim), dtype=complex)

        for i in range(self.n_visible):
            H -= a[i] * single_op(Z, i)
        for j in range(self.n_hidden):
            H -= b[j] * single_op(Z, self.n_visible + j)
        for i in range(self.n_visible):
            for j in range(self.n_hidden):
                H -= W[i, j] * single_op(Z, i) @ single_op(Z, self.n_visible + j)
        for k in range(self.n_total):
            H -= gamma * single_op(X, k)

        return H

    def quantum_rbm_distribution(self, W: np.ndarray, a: np.ndarray, b: np.ndarray, gamma: float, beta: float = 1.0) -> np.ndarray:
        H = self._build_hamiltonian(W, a, b, gamma)
        exp_H = expm(-beta * H)
        rho = exp_H / np.trace(exp_H)
        rho_reshaped = rho.reshape(self.dim_v, self.dim_h, self.dim_v, self.dim_h)
        rho_v = np.einsum('ijik->jk', rho_reshaped)
        return np.real(np.diag(rho_v))

    def kl_divergence(self, p: np.ndarray, q: np.ndarray) -> float:
        eps = 1e-10
        p = np.clip(p, eps, 1)
        q = np.clip(q, eps, 1)
        return np.sum(p * np.log(p / q))

    def generate_target_distribution(self, distribution_type: str) -> np.ndarray:
        if distribution_type == 'uniform':
            return np.ones(self.dim_v) / self.dim_v
        elif distribution_type == 'peaked':
            probs = np.exp(-2 * np.arange(self.dim_v))
            return probs / np.sum(probs)
        elif distribution_type == 'bimodal':
            probs = np.zeros(self.dim_v)
            probs[0] = 1.0
            probs[-1] = 1.0
            return probs / np.sum(probs)
        elif distribution_type == 'quantum':
            probs = np.abs(np.random.randn(self.dim_v) + 1j * np.random.randn(self.dim_v))**2
            return probs / np.sum(probs)
        return np.ones(self.dim_v) / self.dim_v

    def fit_classical_rbm(self, target: np.ndarray, n_iterations: int = 100) -> Tuple[float, Dict]:
        W = np.random.randn(self.n_visible, self.n_hidden) * 0.1
        a = np.random.randn(self.n_visible) * 0.1
        b = np.random.randn(self.n_hidden) * 0.1
        lr = 0.1

        for _ in range(n_iterations):
            eps = 1e-4
            for i in range(self.n_visible):
                a[i] += eps
                kl_plus = self.kl_divergence(target, self.classical_rbm_distribution(W, a, b))
                a[i] -= 2*eps
                kl_minus = self.kl_divergence(target, self.classical_rbm_distribution(W, a, b))
                a[i] += eps
                a[i] -= lr * (kl_plus - kl_minus) / (2*eps)

        final_dist = self.classical_rbm_distribution(W, a, b)
        return self.kl_divergence(target, final_dist), {'W': W, 'a': a, 'b': b}

    def fit_quantum_rbm(self, target: np.ndarray, gamma: float, n_iterations: int = 100) -> Tuple[float, Dict]:
        W = np.random.randn(self.n_visible, self.n_hidden) * 0.1
        a = np.random.randn(self.n_visible) * 0.1
        b = np.random.randn(self.n_hidden) * 0.1
        lr = 0.1

        for _ in range(n_iterations):
            eps = 1e-4
            for i in range(self.n_visible):
                a[i] += eps
                kl_plus = self.kl_divergence(target, self.quantum_rbm_distribution(W, a, b, gamma))
                a[i] -= 2*eps
                kl_minus = self.kl_divergence(target, self.quantum_rbm_distribution(W, a, b, gamma))
                a[i] += eps
                a[i] -= lr * (kl_plus - kl_minus) / (2*eps)

        final_dist = self.quantum_rbm_distribution(W, a, b, gamma)
        return self.kl_divergence(target, final_dist), {'W': W, 'a': a, 'b': b, 'gamma': gamma}

    def run_comparison(self) -> Dict:
        results = {}
        for dist_type in ['uniform', 'peaked', 'bimodal', 'quantum']:
            target = self.generate_target_distribution(dist_type)
            kl_classical, _ = self.fit_classical_rbm(target, n_iterations=50)
            kl_quantum, _ = self.fit_quantum_rbm(target, gamma=0.5, n_iterations=50)
            results[dist_type] = {
                'classical_kl': kl_classical,
                'quantum_kl': kl_quantum,
                'quantum_advantage': kl_classical - kl_quantum
            }
        return results
